INSERT INTO articles (title, date, category, summary, content, cover_url) VALUES
('Acmerd 正式上线', '2026-04-30', '公告', '企业信息收录平台 Acmerd 正式上线，提供企业作息、薪资等信息查询服务。', '<p>欢迎来到 Acmerd！</p><p>我们是一个专注于企业信息收录的平台，致力于为用户提供透明、真实的企业工作环境信息。</p><h2>我们的使命</h2><p>帮助求职者了解目标企业的真实工作状态，做出更明智的职业选择。</p><h2>主要功能</h2><ul><li>企业信息查询</li><li>薪资水平参考</li><li>工作时间统计</li><li>员工评价分享</li></ul>', 'https://images.unsplash.com/photo-1486406146926-c627a92ad1ab?w=1464&h=600&fit=crop'),

('如何使用企业筛选功能', '2026-04-29', '教程', '详细讲解如何使用 Acmerd 的企业筛选功能，快速找到你关心的企业信息。', '<h2>企业筛选功能介绍</h2><p>Acmerd 提供多维度企业筛选功能，帮助你快速定位目标企业。</p><h3>筛选条件</h3><ul><li>城市：按工作地点筛选</li><li>行业：按行业分类筛选</li><li>规模：按公司规模筛选</li><li>标签：按特色标签筛选</li></ul><h3>使用技巧</h3><p>组合使用多个筛选条件可以更精准地找到目标企业。</p>', 'https://images.unsplash.com/photo-1497366216548-37526070297c?w=1464&h=600&fit=crop'),

('2026 年互联网行业薪资报告', '2026-04-28', '数据', '基于 Acmerd 收录的企业数据，分析 2026 年互联网行业薪资趋势。', '<h2>2026 互联网薪资趋势</h2><p>基于平台收录的 500+ 家企业数据，我们整理了这份薪资报告。</p><h3>各城市薪资水平</h3><ul><li>北京：平均月薪 25K-35K</li><li>上海：平均月薪 23K-32K</li><li>深圳：平均月薪 22K-30K</li><li>杭州：平均月薪 20K-28K</li></ul><h3>岗位差异</h3><p>技术岗位普遍高于非技术岗位 30%-50%。</p>', 'https://images.unsplash.com/photo-1460925895917-afdab827c52f?w=1464&h=600&fit=crop'),

('职场新人避坑指南', '2026-04-27', '经验', '写给刚入职场的朋友，分享如何避免常见职场陷阱。', '<h2>职场新人必看</h2><p>刚入职场，有很多坑需要避免。以下是一些实用建议：</p><h3>1. 了解公司真实情况</h3><p>入职前通过 Acmerd 查询企业作息、薪资等信息，避免踩坑。</p><h3>2. 谈薪技巧</h3><p>不要只盯着底薪，要看整体薪酬包（奖金、期权、福利）。</p><h3>3. 职业发展</h3><p>选择有成长空间的公司，比选择高薪但无成长的公司更重要。</p>', 'https://images.unsplash.com/photo-1521737711867-e3b97375f902?w=1464&h=600&fit=crop'),

('996 还是 965？企业作息大揭秘', '2026-04-26', '调查', '调查 200+ 家互联网企业的真实工作时间，数据说话。', '<h2>工作时间调查</h2><p>我们调查了平台上 200+ 家企业的真实工作时间。</p><h3>调查结果</h3><ul><li>严格执行 965 的企业：35%</li><li>弹性工作制的企业：40%</li><li>存在加班文化的企业：25%</li></ul><h3>行业差异</h3><p>游戏行业加班最严重，外企普遍作息最规律。</p>', 'https://images.unsplash.com/photo-1507537297725-24a1c029d3ca?w=1464&h=600&fit=crop');

